  WITH EODDATE AS
(
    SELECT EOD_DATE FROM "ODS".TB_EODODS_EOD_DATE
)
,UPX_ANNA_DSB AS
(
    SELECT *
    FROM "FMODS".TB_UPXFMO_UPI_ANNADSB_REF_RATE
    WHERE SYS_VALUE_DATE = (SELECT MAX(SYS_VALUE_DATE) FROM "FMODS".TB_UPXFMO_UPI_ANNADSB_REF_RATE)
)
,QRF_DATA AS
(
    SELECT *
    FROM "FMODS".TB_QRFFMO_QRD_TRADE_FULL QRF
    WHERE
        QRF.SYS_VALUE_DATE = (SELECT EOD_DATE FROM EODDATE)
        AND
        (
            QRF.QRF_CANADA_REPORTING_PTY = 'Y'
            OR QRF.QRF_CFTC_REPORTING_PARTY = 'Y'
            OR QRF.QRF_SEC_REPORTING_PARTY = 'Y'
        )
)

,OTH_PAYER_LIST AS
(
    SELECT
        PAYER_LIST_ITEM.QRF_SID
        ,PAYER_LIST_ITEM.QRF_CDE_OTHER_PMT_PAYER
        ,LISTAGG(PAYER_LIST_ITEM.PAYER_LIST_ITEM_VALUE,';' ON OVERFLOW TRUNCATE WITHOUT COUNT) WITHIN GROUP(ORDER BY PAYER_LIST_ITEM.LIST_INDEX) AS PAYER_LIST
        ,LISTAGG(PAYER_LIST_ITEM.PAYER_TYPE_LIST_ITEM_VALUE,';' ON OVERFLOW TRUNCATE WITHOUT COUNT) WITHIN GROUP(ORDER BY PAYER_LIST_ITEM.LIST_INDEX) AS PAYER_TYPE_LIST
    FROM
    (
        SELECT
            PAYER_VPIVOT.*
            ,RPY.RPY_LEI_NO
            ,RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG
            ,RPY_CPTY_ID_SRC_NAT_PERS_FLG
            ,RPY.RPY_PTY_REF_ID
            ,RPY_PTY_NAME
            ,CASE
                WHEN RPY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY.RPY_PTY_REF_ID,RPY.RPY_LEI_NO)
                WHEN RPY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN 'BSGEFEIOM18Y80CKCV46' || RPY.RPY_PTY_NAME
                WHEN PAYER_VPIVOT.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY.RPY_PTY_NAME
                ELSE '???'
             END AS PAYER_LIST_ITEM_VALUE
            ,CASE
                WHEN RPY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y','PLID','LEI')
                WHEN RPY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN 'NPID'
                WHEN PAYER_VPIVOT.QRF_CANADA_REPORTING_PTY = 'Y' THEN 'INTERNAL'
                ELSE '???'
             END AS PAYER_TYPE_LIST_ITEM_VALUE
        FROM
        (
            SELECT
                QRF.SYS_VALUE_DATE
                ,QRF.QRF_SID
                ,QRF.QRF_CDE_OTHER_PMT_PAYER
                ,QRF.QRF_CANADA_REPORTING_PTY
                ,T.COLUMN_VALUE AS LIST_INDEX
                ,TRIM(REGEXP_SUBSTR(QRF.QRF_CDE_OTHER_PMT_PAYER,'[^;]+',1,T.COLUMN_VALUE)) AS PAYER
            FROM
                QRF_DATA QRF
                CROSS JOIN TABLE
                (
                    CAST
                    (
                        MULTISET
                        (
                            SELECT LEVEL FROM DUAL CONNECT BY INSTR(QRF.QRF_CDE_OTHER_PMT_PAYER,';',1,LEVEL-1) > 0
                        )
                        AS SYS.ODCINUMBERLIST
                    )
                ) T
            WHERE
                QRF.QRF_CDE_OTHER_PMT_PAYER IS NOT NULL
        ) PAYER_VPIVOT
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY	RPY ON
        (
            PAYER_VPIVOT.PAYER = RPY.RPY_COUNTERPARTY_MUREX_CODE
            AND PAYER_VPIVOT.SYS_VALUE_DATE = RPY.RPY_VALUE_DATE
        )
    ) PAYER_LIST_ITEM
    GROUP BY
        PAYER_LIST_ITEM.QRF_SID
        ,PAYER_LIST_ITEM.QRF_CDE_OTHER_PMT_PAYER
)
,OTH_RECEIVER_LIST AS
(
  	SELECT
        RECEIVER_LIST_ITEM.QRF_SID
        ,RECEIVER_LIST_ITEM.QRF_CDE_OTHER_PMT_RECEIVER
        ,LISTAGG(RECEIVER_LIST_ITEM.RECEIVER_LIST_ITEM_VALUE,';' ON OVERFLOW TRUNCATE WITHOUT COUNT) WITHIN GROUP(ORDER BY RECEIVER_LIST_ITEM.LIST_INDEX) AS RECEIVER_LIST
        ,LISTAGG(RECEIVER_LIST_ITEM.RECEIVER_TYPE_LIST_ITEM_VALUE,';' ON OVERFLOW TRUNCATE WITHOUT COUNT) WITHIN GROUP(ORDER BY RECEIVER_LIST_ITEM.LIST_INDEX) AS RECEIVER_TYPE_LIST
    FROM
    (
        SELECT
            RECEIVER_VPIVOT.*
            ,RPY.RPY_LEI_NO
            ,RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG
            ,RPY_CPTY_ID_SRC_NAT_PERS_FLG
            ,RPY.RPY_PTY_REF_ID
            ,RPY_PTY_NAME
            ,CASE
                WHEN RPY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY.RPY_PTY_REF_ID,RPY.RPY_LEI_NO)
                WHEN RPY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN 'BSGEFEIOM18Y80CKCV46' || RPY.RPY_PTY_NAME
                WHEN RECEIVER_VPIVOT.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY.RPY_PTY_NAME
                ELSE '???'
             END AS RECEIVER_LIST_ITEM_VALUE
            ,CASE
                WHEN RPY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y','PLID','LEI')
                WHEN RPY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN 'NPID'
                WHEN RECEIVER_VPIVOT.QRF_CANADA_REPORTING_PTY = 'Y' THEN 'INTERNAL'
                ELSE '???'
             END AS RECEIVER_TYPE_LIST_ITEM_VALUE
        FROM
        (
            SELECT
                QRF.SYS_VALUE_DATE
                ,QRF.QRF_SID
                ,QRF.QRF_CDE_OTHER_PMT_RECEIVER
                ,QRF.QRF_CANADA_REPORTING_PTY
                ,T.COLUMN_VALUE AS LIST_INDEX
                ,TRIM(REGEXP_SUBSTR(QRF.QRF_CDE_OTHER_PMT_RECEIVER,'[^;]+',1,T.COLUMN_VALUE)) AS RECEIVER
            FROM
                QRF_DATA QRF
                CROSS JOIN TABLE
                (
                    CAST
                    (
                        MULTISET
                        (
                            SELECT LEVEL FROM DUAL CONNECT BY INSTR(QRF.QRF_CDE_OTHER_PMT_RECEIVER,';',1,LEVEL-1) > 0
                        )
                        AS SYS.ODCINUMBERLIST
                    )
                ) T
            WHERE
                QRF.QRF_CDE_OTHER_PMT_RECEIVER IS NOT NULL
        ) RECEIVER_VPIVOT
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY	RPY ON
        (
            RECEIVER_VPIVOT.RECEIVER = RPY.RPY_COUNTERPARTY_MUREX_CODE
            AND RECEIVER_VPIVOT.SYS_VALUE_DATE = RPY.RPY_VALUE_DATE
        )
    ) RECEIVER_LIST_ITEM
    GROUP BY
        RECEIVER_LIST_ITEM.QRF_SID
        ,RECEIVER_LIST_ITEM.QRF_CDE_OTHER_PMT_RECEIVER
)
,UNDRL_ASSET_ID_LIST AS
(
    SELECT
        UNDERL_ASSET_ID_LIST_ITEM.QRF_SID
        ,TO_CHAR(UNDERL_ASSET_ID_LIST_ITEM.QRF_UNDRL_ASSET_ID) AS QRF_UNDRL_ASSET_ID
        ,SUBSTR
        (
            XMLCAST
            (
                XMLAGG
                (
                    XMLELEMENT(E,';',UNDERL_ASSET_ID_LIST_ITEM.CUSTOM_BSK_CONST_UNIT_MEAS)
                    ORDER BY UNDERL_ASSET_ID_LIST_ITEM.LIST_INDEX
                ) AS CLOB
            ),2,6499
        ) AS CUSTOM_BSK_CONST_UNIT_MEAS
        ,SUBSTR
        (
            XMLCAST
            (
                XMLAGG
                (
                    XMLELEMENT(E,';',REPLACE(TRANSLATE(UNDERL_ASSET_ID_LIST_ITEM.CUSTOM_BSK_CONST_ID_SRC,'-!,@#$%^&*()+=<>~\/{}[]|;:)"''',' ' ),' ',NULL))
                    ORDER BY UNDERL_ASSET_ID_LIST_ITEM.LIST_INDEX
                ) AS CLOB
            ),2,6499
        ) AS CUSTOM_BSK_CONST_ID_SRC
    FROM
    (
        SELECT
            UNDRL_ASSET_VPIVOT.*
            ,CASE
                WHEN RIN.RIN_CATEGORIES IN('Equities','Collective Investment Vehicles') THEN 'SHAS'
                WHEN RIN.RIN_CATEGORIES = 'Referential Instruments' THEN 'IPNT'
                ELSE 'EROR'
            END AS CUSTOM_BSK_CONST_UNIT_MEAS
            ,CASE
                WHEN RIN.RIN_CATEGORIES IN('Equities','Collective Investment Vehicles') THEN RIN.RIN_DESC
                WHEN RIN.RIN_CATEGORIES = 'Referential Instruments' THEN 'External'
                ELSE 'EROR'
            END AS CUSTOM_BSK_CONST_ID_SRC
        FROM
        (
            SELECT
                QRF.SYS_VALUE_DATE
                ,QRF.QRF_SID
                ,QRF.QRF_UNDRL_ASSET_ID
                ,T.COLUMN_VALUE AS LIST_INDEX
                ,TO_CHAR(TRIM(REGEXP_SUBSTR(QRF.QRF_UNDRL_ASSET_ID,'[^;]+',1,T.COLUMN_VALUE))) AS UNDRL_ASSET_ID
            FROM
                QRF_DATA QRF
                CROSS JOIN TABLE
                (
                    CAST
                    (
                        MULTISET
                        (
                            SELECT LEVEL FROM DUAL CONNECT BY INSTR(QRF.QRF_UNDRL_ASSET_ID,';',1,LEVEL-1) > 0
                        )
                        AS SYS.ODCINUMBERLIST
                    )
                ) T
            WHERE
                QRF.QRF_UNDRL_ASSET_ID IS NOT NULL
        ) UNDRL_ASSET_VPIVOT
        LEFT JOIN "FMODS".TB_RINFMO_REF_INSTR RIN ON
        (
            UNDRL_ASSET_VPIVOT.UNDRL_ASSET_ID = RIN.RIN_BB_TICKER_ID
            AND UNDRL_ASSET_VPIVOT.SYS_VALUE_DATE = RIN.RIN_VALUE_DATE
        )
    ) UNDERL_ASSET_ID_LIST_ITEM
    GROUP BY
        UNDERL_ASSET_ID_LIST_ITEM.QRF_SID
        ,TO_CHAR(UNDERL_ASSET_ID_LIST_ITEM.QRF_UNDRL_ASSET_ID)
)


,FINAL_DATA AS
(
    SELECT
        CASE
            WHEN sub_jurisdiction.JURISDICTION IN('CFTC','SECH','MIXX') THEN 'Y'
            ELSE 'N'
        END AS REPORTABLE_CFTC

        ,QRF.QRF_CANADA_REPORTING_PTY AS REPORTABLE_CSA

        ,QRF.QRF_CLRNG_STATUS AS CLEARED

        ,RPY_LE.RPY_LEI_NO AS REPORTING_PARTY_LEI

        ,CASE
            WHEN RPY_CPTY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_CPTY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY_CPTY.RPY_PTY_REF_ID,RPY_CPTY.RPY_LEI_NO)
            WHEN RPY_CPTY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN RPY_LE.RPY_LEI_NO || RPY_CPTY.RPY_PTY_NAME
            --WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY_CPTY.RPY_PTY_NAME
            ELSE NULL
         END AS COUNTERPARTY_LEI

        ,CASE
            WHEN RPY_CPTY.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_CPTY.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y','PLID','LEID')
            WHEN RPY_CPTY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN 'NPID'
            --WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN 'Internal'
         END AS PARTY_TYP2

        ,'TRUE' AS FINANCIAL_ENTITY1

        ,DECODE(RPY_CPTY.RPY_FINANCIAL_ENTITY,'Y','true','False') AS FINANCIAL_ENTITY2

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('Equity','Credit') THEN
                CASE
                    WHEN RPY_BUYER_ID.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_BUYER_ID.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY_BUYER_ID.RPY_PTY_REF_ID,RPY_BUYER_ID.RPY_LEI_NO)
                    WHEN RPY_BUYER_ID.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN RPY_LE.RPY_LEI_NO || RPY_BUYER_ID.RPY_PTY_NAME
                    WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY_BUYER_ID.RPY_PTY_NAME
                    ELSE NULL
                 END
            ELSE NULL
         END AS BUYER

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('Equity','Credit') THEN
                CASE
                    WHEN RPY_SELLER_ID.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_SELLER_ID.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY_SELLER_ID.RPY_PTY_REF_ID,RPY_SELLER_ID.RPY_LEI_NO)
                    WHEN RPY_SELLER_ID.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN RPY_LE.RPY_LEI_NO || RPY_SELLER_ID.RPY_PTY_NAME
                    WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY_SELLER_ID.RPY_PTY_NAME
                    ELSE NULL
                 END
            ELSE NULL
         END AS SELLER

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Equity') THEN
                CASE
                    WHEN RPY_PAYER1.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_PAYER1.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY_PAYER1.RPY_PTY_REF_ID,RPY_PAYER1.RPY_LEI_NO)
                    WHEN RPY_PAYER1.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN RPY_LE.RPY_LEI_NO || RPY_PAYER1.RPY_PTY_NAME
                    WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY_PAYER1.RPY_PTY_NAME
                    ELSE NULL
                 END
            ELSE NULL
         END AS PAYER_LEG1

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Equity') THEN
                CASE
                    WHEN RPY_PAYER2.RPY_LEI_NO IS NOT NULL THEN DECODE(RPY_PAYER2.RPY_CPTY_ID_SRC_PRV_LAW_FLG,'Y',RPY_PAYER2.RPY_PTY_REF_ID,RPY_PAYER2.RPY_LEI_NO)
                    WHEN RPY_PAYER2.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN RPY_LE.RPY_LEI_NO || RPY_PAYER2.RPY_PTY_NAME
                    WHEN QRF.QRF_CANADA_REPORTING_PTY = 'Y' THEN RPY_PAYER2.RPY_PTY_NAME
                    ELSE NULL
                 END
            ELSE NULL
         END AS PAYER_LEG2

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Equity') THEN
                CASE
