         END AS UPI_UNDRLNG_INSTR_TERM_UNT

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Credit' THEN QRF.QRF_UPI_UNDRL_INST_IDX_TERMVAL
            ELSE NULL
         END AS UPI_UNDRLNG_INSTR_TERM_VAL

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN
                CASE
                    WHEN NVL(sub_underlier.UPI_UNDERLIER_CHAR,' ') != 'Basket' THEN RIN_UNDERL.RIN_ISIN_ID
                    ELSE NULL
                END
            ELSE NULL
         END AS UPI_UNDRLNG_INSTR_ISIN

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Credit' THEN QRF.QRF_UPI_UNDRL_INSTR_UPI
            ELSE NULL
         END AS UPI_UNDRLNG_INSTR_UPI

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Credit' THEN RIN_UNDERL_CRD.RIN_CFI_UNDERL_ISSUER_TYPE
            ELSE NULL
         END AS UPI_UNDRLNG_ISSUER_TYPE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN DECODE(QRF.QRF_UPI_INSTR_TYPE,'Option','Other',NULL)
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Credit' THEN QRF.QRF_UPI_VALUATN_METHOD_OR_TRIG
            ELSE NULL
         END AS UPI_VALUATION_METHOD_TRIGGER

        ,QRF.QRF_UPI_DELIVERY_TYPE AS UPI_CFI_DELIVERY_TYPE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN DECODE(QRF.QRF_UPI_INSTR_TYPE,'Option',QRF.QRF_UPI_OPT_EXERCS_STYLE || '-' || QRF.QRF_UPI_OPT_TYPE)
            ELSE NULL
         END AS UPI_CFI_OPTION_STYLE_TYPE

        ,QRF.QRF_UPI_CLASSICATION_TYPE AS UPI_CLASSIFICATION_TYPE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN QRF.QRF_UPI_SINGLE_OR_MULT_CCY
            ELSE NULL
         END AS UPI_SINGLE_MULTI_CURR

        ,QRF.QRF_UPI_DSB_UPI AS UPI_DSB_UPI

        ,PAY_LIST.PAYER_TYPE_LIST AS OTH_PAYMENT_PAYER_TYPE

        ,RECV_LIST.RECEIVER_TYPE_LIST AS OTH_PAYMENT_RECEIVER_TYPE

        ,QRF.QRF_UPI_DSB_UPI AS UNIQUE_PRODUCT_IDENTIFIER

        ,'TCTN' AS LEVEL_RPT

        ,CASE
            WHEN RPY_CPTY.RPY_CPTY_ID_SRC_NAT_PERS_FLG = 'Y' THEN
                CASE
                    WHEN RPY_CPTY.RPY_CPTY_HQ_CNTRY_ISO_CODE = 'CAN' THEN sub_jurisdiction.LOCAL_JURISDICTION_LIST_PROV_CPTY
                    ELSE RPY_CPTY.RPY_CPTY_HQ_CNTRY_ISO_CODE
                END
            ELSE NULL
         END AS TP2_IND_PROVINCE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND QRF.QRF_UNDRL_ASSET_ID_TYPE = 'Basket' THEN UNDRL_ASSET_ID_LIST.CUSTOM_BSK_CONST_UNIT_MEAS
            ELSE NULL
         END AS CUSTOM_BSK_CONST_UNIT_MEAS

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND QRF.QRF_UNDRL_ASSET_ID_TYPE = 'Basket' THEN UNDRL_ASSET_ID_LIST.CUSTOM_BSK_CONST_ID_SRC
            ELSE NULL
         END AS CUSTOM_BSK_CONST_ID_SRC

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND QRF.QRF_UNDRL_ASSET_ID_TYPE = 'Basket' THEN 'BSGEFEIOM18Y80CKCV46' || QRF.QRF_UTI_ID
            ELSE NULL
         END CUSTOM_BSK_CODE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND QRF.QRF_UNDRL_ASSET_ID_TYPE = 'Basket' THEN QRF.QRF_UNDRL_ASSET_ID
            ELSE NULL
         END CUSTOM_BSK_CONST_ID

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND NVL(QRF.QRF_UNDRL_ASSET_ID_TYPE,' ') != 'Basket' THEN
                CASE
                    WHEN RIN_UNDERL.RIN_CATEGORIES = 'Referential Instruments' AND TRIM(RIN_UNDERL.RIN_ISIN_ID) IS NULL AND TRIM(RIN_UNDERL.RIN_PROPRIETARY_INDICES) IS NULL AND TRIM(RIN_UNDERL.RIN_DSB_ENUM_IDX_NAME) IS NULL THEN TO_CHAR(QRF.QRF_UNDRL_ASSET_ID)
                    ELSE NULL
                END
            ELSE NULL
         END AS UNDERLIER_ID_OTHR_LEG1

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND NVL(QRF.QRF_UNDRL_ASSET_ID_TYPE,' ') != 'Basket' THEN
                CASE
                    WHEN RIN_UNDERL.RIN_CATEGORIES = 'Referential Instruments' AND TRIM(RIN_UNDERL.RIN_ISIN_ID) IS NULL AND TRIM(RIN_UNDERL.RIN_PROPRIETARY_INDICES) IS NULL AND TRIM(RIN_UNDERL.RIN_DSB_ENUM_IDX_NAME) IS NULL THEN 'External'
                    ELSE NULL
                END
            ELSE NULL
         END AS UNDERLYING_PRICE_SRC_LEG1

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' AND NVL(QRF.QRF_UNDRL_ASSET_ID_TYPE,' ') != 'Basket' THEN
                CASE
                    WHEN RIN_UNDERL.RIN_CATEGORIES = 'Referential Instruments' AND TRIM(RIN_UNDERL.RIN_ISIN_ID) IS NULL AND TRIM(RIN_UNDERL.RIN_PROPRIETARY_INDICES) IS NULL AND TRIM(RIN_UNDERL.RIN_DSB_ENUM_IDX_NAME) IS NULL THEN 'External'
                    ELSE NULL
                END
            ELSE NULL
         END AS UNDERLIER_ID_OTHR_SRC_LEG1

        ,sub_dcm_anonym.SEF_DCM_ANONYM

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN QRF.QRF_EFFECT_DATE_STRIKE
            ELSE NULL
         END AS EFFECTI_DATE_STRIKE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN QRF.QRF_STRIKE_PRICE_SCHDL
            ELSE NULL
         END AS STRIKE_SCHEDULE

        ,CASE
            WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN QRF.QRF_BASKET_CONST_NB_UNIT
            ELSE NULL
         END AS CUSTOM_BSK_CONST_NB_UNIT
    FROM
        QRF_DATA QRF
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY	RPY_LE ON
        (
            QRF.QRF_TRD_PTY_ID_1 = RPY_LE.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_LE.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY	RPY_CPTY ON
        (
            QRF.QRF_TRD_PTY_ID_2 = RPY_CPTY.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_CPTY.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_SEF ON
        (
            QRF.QRF_EXECUTION_VENUE_ID = RPY_SEF.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_SEF.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_BRK ON
        (
            QRF.QRF_TRD_PTY_BKR_ID1 = RPY_BRK.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_BRK.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_PAYER1 ON
        (
            QRF.QRF_PAYER_ID1 = RPY_PAYER1.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_PAYER1.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_PAYER2 ON
        (
            QRF.QRF_PAYER_ID2 = RPY_PAYER2.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_PAYER2.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_RECEIVER1 ON
        (
            QRF.QRF_PMT_1_RECVR = RPY_RECEIVER1.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_RECEIVER1.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_RECEIVER2 ON
        (
            QRF.QRF_LEG_2_CDE_RECEIVER_ID = RPY_RECEIVER2.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_RECEIVER2.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_BUYER_ID ON
        (
            QRF.QRF_BUYER_ID = RPY_BUYER_ID.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_BUYER_ID.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPYFMO_REF_PTY RPY_SELLER_ID ON
        (
            QRF.QRF_SELLER_ID = RPY_SELLER_ID.RPY_COUNTERPARTY_MUREX_CODE
            AND QRF.SYS_VALUE_DATE = RPY_SELLER_ID.RPY_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RPIFMO_REF_PTY_ID RPI ON
        (
            RPY_LE.RPY_AGENT_ID = RPI.RPY_PTY_REF_ID
            AND QRF.SYS_VALUE_DATE = RPI.RPI_VALUE_DATE
            AND RPI.RPI_ROLE_SYS_VAL = 'MIDAS'
        )
        LEFT JOIN "FMODS".TB_MLGFMO_MASTR_LEGL_AGRE MLG ON
        (
            RPI.RPI_PTY_SRC_NK = MLG.MLG_ENTITY_CODE
            AND RPY_CPTY.RPY_PARNT_REF_ID = MLG.MLG_CPTY_CODE
            AND QRF.SYS_VALUE_DATE = MLG.SYS_VALUE_DATE
            AND MLG.MLG_ACTIVE_FLG = 'Y'
            AND MLG.MLG_AGREEMENT_TYPE = 'ISD'
        )
        LEFT JOIN OTH_PAYER_LIST PAY_LIST ON
        (
            QRF.QRF_SID = PAY_LIST.QRF_SID
        )
        LEFT JOIN OTH_RECEIVER_LIST RECV_LIST ON
        (
            QRF.QRF_SID = RECV_LIST.QRF_SID
        )
        LEFT JOIN UPX_ANNA_DSB UPX_LEG1 ON
        (
            QRF.QRF_FLOAT_RATE_IDX1 = UPX_LEG1.UPX_RATES_CODE
        )
        LEFT JOIN UPX_ANNA_DSB UPX_LEG2 ON
        (
            QRF.QRF_FLOAT_RATE_IDX2 = UPX_LEG2.UPX_RATES_CODE
        )
        LEFT JOIN "FMODS".TB_RINFMO_REF_INSTR RIN_UNDERL ON
        (
            TO_CHAR(QRF.QRF_UNDRL_ASSET_ID) = RIN_UNDERL.RIN_BB_TICKER_ID
            AND QRF.SYS_VALUE_DATE = RIN_UNDERL.RIN_VALUE_DATE
        )
        LEFT JOIN "FMODS".TB_RIIFMO_REF_INSTR_ID RII_UNDERL ON
        (
            TO_CHAR(QRF.QRF_UNDRL_ASSET_ID) = RII_UNDERL.RII_INSTR_SYS_ID
            AND QRF.SYS_VALUE_DATE = RII_UNDERL.RII_VALUE_DATE
            AND RII_UNDERL.RII_ID_TP_CODE = 'MUREX'
        )
        LEFT JOIN "FMODS".TB_RINFMO_REF_INSTR RIN_UNDERL_CRD ON
        (
            RII_UNDERL.RIN_SID = RIN_UNDERL_CRD.RIN_SID
            AND QRF.SYS_VALUE_DATE = RIN_UNDERL_CRD.RIN_VALUE_DATE
        )
        LEFT JOIN UNDRL_ASSET_ID_LIST ON
        (
            QRF.QRF_SID = UNDRL_ASSET_ID_LIST.QRF_SID
        )
        CROSS APPLY
        (
            SELECT
                LTRIM
                (
                    DECODE(RPY_CPTY.RPY_CA_AL_REPORT_FLG,'Y',',CA.AB.ASC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_BC_REPORT_FLG,'Y',',CA.BC.BCSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_MA_REPORT_FLG,'Y',',CA.MB.MSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NB_REPORT_FLG,'Y',',CA.NB.FCSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NL_REPORT_FLG,'Y',',CA.NL.DSS',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NT_REPORT_FLG,'Y',',CA.NT.NTSO',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NS_REPORT_FLG,'Y',',CA.NS.NSSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NU_REPORT_FLG,'Y',',CA.NU.NSO',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_ON_REPORT_FLG,'Y',',CA.ON.OSC',NULL) ||
                    ',CA.QC.AMF' ||
                    DECODE(RPY_CPTY.RPY_CA_PE_REPORT_FLG,'Y',',CA.PEI.OSS',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_SK_REPORT_FLG,'Y',',CA.SK.FCAA',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_YT_REPORT_FLG,'Y',',CA.YT.OSS',NULL)
                    ,','
                ) AS REP_DESTINATION_1
                ,LTRIM
                (
                    DECODE(RPY_CPTY.RPY_CA_AL_REPORT_FLG,'Y',',CA.AB.ASC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_BC_REPORT_FLG,'Y',',CA.BC.BCSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_MA_REPORT_FLG,'Y',',CA.MB.MSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NB_REPORT_FLG,'Y',',CA.NB.FCSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NL_REPORT_FLG,'Y',',CA.NL.DSS',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NT_REPORT_FLG,'Y',',CA.NT.NTSO',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NS_REPORT_FLG,'Y',',CA.NS.NSSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NU_REPORT_FLG,'Y',',CA.NU.NSO',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_ON_REPORT_FLG,'Y',',CA.ON.OSC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_QC_REPORT_FLG,'Y',',CA.QC.AMF',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_PE_REPORT_FLG,'Y',',CA.PEI.OSS',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_SK_REPORT_FLG,'Y',',CA.SK.FCAA',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_YT_REPORT_FLG,'Y',',CA.YT.OSS',NULL)
                    ,','
                )  AS LOCAL_CPT_JURISDICTION2
                ,LTRIM
                (
                    DECODE(RPY_CPTY.RPY_CA_AL_REPORT_FLG,'Y',',CA-AB',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_BC_REPORT_FLG,'Y',',CA-BC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_MA_REPORT_FLG,'Y',',CA-MB',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NB_REPORT_FLG,'Y',',CA-NB',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NL_REPORT_FLG,'Y',',CA-NL',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NT_REPORT_FLG,'Y',',CA-NT',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NS_REPORT_FLG,'Y',',CA-NS',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_NU_REPORT_FLG,'Y',',CA-NU',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_ON_REPORT_FLG,'Y',',CA-ON',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_QC_REPORT_FLG,'Y',',CA-QC',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_PE_REPORT_FLG,'Y',',CA-PEI',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_SK_REPORT_FLG,'Y',',CA-SK',NULL) ||
                    DECODE(RPY_CPTY.RPY_CA_YT_REPORT_FLG,'Y',',CA-YT',NULL)
                    ,','
                )  AS LOCAL_JURISDICTION_LIST_PROV_CPTY
                ,CASE
                    WHEN QRF.QRF_CDE_EFFECT_DATE < TO_DATE('2021-08-16','YYYY-MM-DD') AND QRF.QRF_TRD_PTY_ID_2 IN('CP/PUGET.SOUND','CP/MATOAKA','CP/JH.INVEST','CP/JET.INFRAST','CP/GATEWAY','CP/IDAHO.WIN.P1','CP/WEAVER.WIND','CP/CHESA.FUN.II','CP/RED.ROCHEST','CP/TAY.E.HOLDCO','CP/CCL.JW.USA','CP/CORDEL.IH.1','CP/ACADIA.BORRO','CP/AMF.ASTRO','BK/JPMCHASE.NY','CP/SOLOTECH.US','CP/GR.LACAS.USA','CP/BOSTON.AFC','CP/CPV.THREE.RI','CP/FEN.WATT.USI','CP/BLUESTON.BAL') THEN 'CFTC'
                    WHEN QRF.QRF_MIXED_SWAPS = 'Y' THEN 'MIXX'
                    WHEN NVL(QRF.QRF_MIXED_SWAPS,' ') != 'Y' AND QRF.QRF_SEC_REPORTING_PARTY = 'Y' AND RPY_CPTY.RPY_US_DETERMNTN_STATUS_FLG = 'Y' THEN 'SECH'
                    WHEN QRF.QRF_ANE = 'Y' THEN 'SECH'
                    WHEN QRF.QRF_CDE_EFFECT_DATE >= TO_DATE('2021-08-16','YYYY-MM-DD') AND NVL(QRF.QRF_MIXED_SWAPS,' ') != 'Y' AND QRF.QRF_CFTC_REPORTING_PARTY = 'Y' AND RPY_CPTY.RPY_US_DETERMNTN_STATUS_FLG = 'Y' THEN 'CFTC'
                    ELSE NULL
                END AS JURISDICTION
            FROM DUAL
        ) sub_jurisdiction
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN QRF.QRF_EXECUTION_VENUE_ID IS NOT NULL THEN RPY_SEF.RPY_LEI_NO
                    ELSE NULL
                END AS EXECUTION_VENUE
            FROM DUAL
        ) sub_execution_venue
        CROSS APPLY
        (
            SELECT
                 CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN DECODE(QRF.QRF_UPI_PRODUCT,'Non_Standard',QRF.QRF_UPI_UNDRL_CHAR,NULL)
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN QRF.QRF_UPI_UNDRL_CHAR
                    ELSE NULL
                 END AS UPI_UNDERLIER_CHAR
                ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN TO_CLOB(QRF.QRF_FLOAT_RATE_IDX1)
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN TO_CLOB(QRF.QRF_UNDRL_ASSET_ID)
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Credit' THEN TO_CLOB(RIN_UNDERL_CRD.RIN_RED_CODE_ID)
                    ELSE NULL
                 END AS UNDERLIER_ID_LEG1
            FROM DUAL
        ) sub_underlier
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN QRF.QRF_INIT_FIX_RATE1
                    ELSE NULL
                 END AS FIXED_RATE1
                ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN QRF.QRF_INIT_FIX_RATE2
                    ELSE NULL
                 END AS FIXED_RATE2
            FROM DUAL
        ) sub_fixed_rate
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Credit') THEN QRF.QRF_LEG_1_SPRD_AMT
                    ELSE NULL
                 END AS SPREAD1
                ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Equity') THEN QRF.QRF_LEG_2_SPRD_AMT
                    ELSE NULL
                 END AS SPREAD2
               ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'InterestRate' THEN QRF.QRF_LEG_1_CDE_SPREAD_NOTATION
                    ELSE NULL
                END AS SPREAD_NOTATION_LEG1
               ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('InterestRate','Equity') THEN QRF.QRF_LEG_2_CDE_SPREAD_NOTATION
                    ELSE NULL
                END AS SPREAD_NOTATION_LEG2
            FROM DUAL
        ) sub_spread
        CROSS APPLY
        (
            SELECT
               CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('Equity','Credit') THEN QRF.QRF_STRIKE_PRICE
                    ELSE NULL
                END AS STRIKE_PRICE
               ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS = 'Equity' THEN QRF.QRF_STRIKE_CCY
                    ELSE NULL
                END AS STRIKE_PRICE_CURR
               ,CASE
                    WHEN QRF.QRF_PRIMARY_ASSET_CLASS IN('Equity','Credit') THEN QRF.QRF_CDE_STRIKE_PX_NOTATION
                    ELSE NULL
                END AS STRIKE_PRICE_NOTATION
            FROM DUAL
        ) sub_strike
        CROSS APPLY
        (
            SELECT CAST(NULL AS VARCHAR2(1 BYTE)) AS SEF_DCM_ANONYM FROM DUAL
        ) sub_dcm_anonym
        CROSS APPLY
        (
            SELECT QRF.QRF_CDE_EFFECT_DATE AS EFFECTIVE_DATE FROM DUAL
        ) sub_effective_date
        CROSS APPLY
		(
            SELECT
                CASE
                    WHEN NVL(sub_dcm_anonym.SEF_DCM_ANONYM,' ') != 'true'
                    THEN DECODE(MLG.MLG_SID, NULL, 'BIAG', 'ISDA')
                    ELSE NULL
                END AS MASTER_AGREEMENT_TYPE
            FROM DUAL
		) sub_agreement_type
)


SELECT/*+ parallel(16)*/
    REPORTABLE_CFTC
    ,REPORTABLE_CSA
	,TO_CHAR(CLEARED) AS CLEARED
	,CAST(NULL AS VARCHAR2(1 BYTE)) AS CLEAR_EXCEPTION2_CFTC
	,CAST(NULL AS VARCHAR2(1 BYTE)) AS CLEAR_EXCEPTION2_CSA
	,TO_CHAR(REPORTING_PARTY_LEI) AS REPORTING_PARTY_LEI
	,TO_CHAR(COUNTERPARTY_LEI) AS COUNTERPARTY_LEI
	,TO_CHAR(PARTY_TYP2) AS PARTY_TYP2
	,TO_CHAR(FINANCIAL_ENTITY1) AS FINANCIAL_ENTITY1
	,TO_CHAR(FINANCIAL_ENTITY2) AS FINANCIAL_ENTITY2
	,TO_CHAR(BUYER) AS BUYER
	,TO_CHAR(SELLER) AS SELLER
	,TO_CHAR(PAYER_LEG1) AS PAYER_LEG1
	,TO_CHAR(PAYER_LEG2) AS PAYER_LEG2
	,TO_CHAR(RECEIVER_LEG1) AS RECEIVER_LEG1
	,TO_CHAR(RECEIVER_LEG2) AS RECEIVER_LEG2
	,TO_CHAR(FEDERAL_ENTITY2) AS FEDERAL_ENTITY2
	,TO_CHAR(CUSTOM_BSK_IND) AS CUSTOM_BSK_IND
	,TO_CHAR(EVENT_ID) AS EVENT_ID
	,TO_CHAR(EVENT_TIME) AS EVENT_TIME
    ,CAST(FMT_ELT.FLEXIBLE_ROUND(NOTIONAL1,2,'HALF_DOWN') AS NUMBER(38,12)) AS NOTIONAL1
	,CAST(FMT_ELT.FLEXIBLE_ROUND(NOTIONAL2,2,'HALF_DOWN') AS NUMBER(38,12)) AS NOTIONAL2
	,TO_CHAR(CURR1) AS CURR1
	,TO_CHAR(CURR2) AS CURR2
	,TO_CHAR(NOTIONAL_AMT_EFFECTI_DATE_LEG1) AS NOTIONAL_AMT_EFFECTI_DATE_LEG1
	,TO_CHAR(NOTIONAL_AMT_EFFECTI_DATE_LEG2) AS NOTIONAL_AMT_EFFECTI_DATE_LEG2
	,TO_CHAR(EFFECTI_DATE_NOTIONAL_AMT_LEG1) AS EFFECTI_DATE_NOTIONAL_AMT_LEG1
	,TO_CHAR(EFFECTI_DATE_NOTIONAL_AMT_LEG2) AS EFFECTI_DATE_NOTIONAL_AMT_LEG2
